struct FenwickTree {
    size: usize,
    tree: Vec<i32>,
}

impl FenwickTree {
    fn new(size: usize) -> Self {
        let tree = vec![0; size + 1];
        Self { size, tree }
    }

    fn update(&mut self, index: usize, delta: i32) {
        let i = index + 1;
        while i <= self.size {
            self.tree[i] += delta;
            i += i & -i;
        }
    }

    fn query(&self, index: usize) -> i32 {
        let mut sum = 0;
        let i = index + 1;
        while i > 0 {
            sum += self.tree[i];
            i -= i & -i;
        }
        sum
    }

    fn range_query(&self, l: usize, r: usize) -> i32 {
        self.query(r) - self.query(l - 1)
    }
}

