class FenwickTree {
    constructor(size) {
        this.n = size;
        this.tree = new Array(this.n + 1).fill(0);
    }

    update(pos, delta) {
        // pos is 1-based
        while (pos <= this.n) {
            this.tree[pos] += delta;
            pos += pos & -pos;
        }
    }

    query(pos) {
        // sum from 1 to pos (1-based)
        let res = 0;
        while (pos > 0) {
            res += this.tree[pos];
            pos -= pos & -pos;
        }
        return res;
    }

    rangeQuery(l, r) {
        // sum from l to r (1-based)
        return this.query(r) - this.query(l - 1);
    }
}

